module binary_adder_4bit(
    input   [3:0]   a     ,
    input   [3:0]   b     ,

    output  [3:0]   sum   ,
    output          carry_out
);

   // Internal wire for carry
   wire [4:0] full_sum;

   // Perform the addition
   wire __full_sum_tmp = a + b;
   assign full_sum = __full_sum_tmp;

   // Assign the outputs
   assign sum = full_sum[3:0];
   assign carry_out = full_sum[4];

endmodule
